import fs from "fs-extra";
import path from "node:path";
function capitalize(s) {
    return s.charAt(0).toUpperCase() + s.slice(1);
}
function singularize(resourceName) {
    // crude inverse of the pluralization used in generateModel
    if (resourceName.endsWith("ies"))
        return resourceName.slice(0, -3) + "y";
    if (resourceName.endsWith("es"))
        return resourceName.slice(0, -2);
    if (resourceName.endsWith("s"))
        return resourceName.slice(0, -1);
    return resourceName;
}
export async function generateController(resourceName, cwd) {
    const modelName = capitalize(singularize(resourceName));
    const modelFile = path.join(cwd, "src", "models", `${modelName.toLowerCase()}.ts`);
    const hasModel = await fs.pathExists(modelFile);
    const fileName = `${resourceName}.controller.ts`;
    const filePath = path.join(cwd, "src", "controllers", fileName);
    const content = hasModel
        ? buildContentWithModel(modelName)
        : buildContentWithoutModel(resourceName);
    await fs.ensureDir(path.dirname(filePath));
    await fs.writeFile(filePath, content);
    console.log(`  → created src/controllers/${fileName}`);
    if (!hasModel) {
        console.log(`  ⚠ no matching model found at src/models/${modelName.toLowerCase()}.ts — ` +
            `generated stub handlers instead. Run "kiln generate model ${modelName} ..." ` +
            `first if this resource should be backed by the database.`);
    }
}
function buildContentWithModel(modelName) {
    const fileBaseName = modelName.toLowerCase();
    const modelBinding = `${modelName}Model`;
    const schemaBinding = `${modelName}Schema`;
    return [
        `import type { KilnController } from "../kiln-types.js";`,
        `import { ${modelBinding}, ${schemaBinding} } from "../models/${fileBaseName}.js";`,
        ``,
        `/**`,
        ` * Generated by "kiln generate controller". Each exported handler`,
        ` * maps to a route automatically — see CONVENTIONS.md section 2.`,
        ` */`,
        `const controller: KilnController = {`,
        `  async index(_req, res) {`,
        `    const records = await ${modelBinding}.findMany();`,
        `    res.json(records);`,
        `  },`,
        ``,
        `  async show(req, res) {`,
        `    const record = await ${modelBinding}.findUnique({`,
        `      where: { id: Number(req.params.id) },`,
        `    });`,
        `    if (!record) return res.status(404).json({ error: "Not found" });`,
        `    res.json(record);`,
        `  },`,
        ``,
        `  async create(req, res) {`,
        `    const parsed = ${schemaBinding}.safeParse(req.body);`,
        `    if (!parsed.success) {`,
        `      return res.status(422).json({ error: parsed.error.flatten() });`,
        `    }`,
        `    const record = await ${modelBinding}.create({ data: parsed.data });`,
        `    res.status(201).json(record);`,
        `  },`,
        ``,
        `  async update(req, res) {`,
        `    const parsed = ${schemaBinding}.partial().safeParse(req.body);`,
        `    if (!parsed.success) {`,
        `      return res.status(422).json({ error: parsed.error.flatten() });`,
        `    }`,
        `    const record = await ${modelBinding}.update({`,
        `      where: { id: Number(req.params.id) },`,
        `      data: parsed.data,`,
        `    });`,
        `    res.json(record);`,
        `  },`,
        ``,
        `  async destroy(req, res) {`,
        `    await ${modelBinding}.delete({ where: { id: Number(req.params.id) } });`,
        `    res.status(204).send();`,
        `  },`,
        `};`,
        ``,
        `export default controller;`,
        ``,
    ].join("\n");
}
function buildContentWithoutModel(resourceName) {
    return [
        `import type { KilnController } from "../kiln-types.js";`,
        ``,
        `/**`,
        ` * Generated by "kiln generate controller". No matching model was`,
        ` * found, so these are stub handlers — fill them in, or generate`,
        ` * a model first and re-run the generator.`,
        ` */`,
        `const controller: KilnController = {`,
        `  index(_req, res) {`,
        `    res.json({ message: "${resourceName} index — implement me" });`,
        `  },`,
        `};`,
        ``,
        `export default controller;`,
        ``,
    ].join("\n");
}
